// ============================================================================
// miles-slack-event-router · Classify Event
// ----------------------------------------------------------------------------
// Resuelve los 3 ejes de clasificacion y devuelve una unica `action`.
//   Eje 1 (que):    tipo de evento Slack
//   Eje 2 (quien):  origen del evento (Claude firmado / Miles / bot / humano)
//   Eje 3 (donde):  canal REQ vs otro · raiz vs reply · con/sin mencion
//
// Acciones posibles:
//   'challenge'        -> (lo maneja un IF previo, no llega aca)
//   'app_home'         -> publicar App Home
//   'capture_req'      -> forward al conversation-handler (captura REQ de Claude)
//   'ignore'           -> noOp
//
// Catalogo (ver miles-discovery.md):
//   1  url_verification                                          -> challenge (IF previo)
//   2  app_home_opened + humano                                  -> app_home
//   3  app_mention + Claude firmado + canal REQ + raiz           -> capture_req
//   4  cualquiera + Miles                                        -> ignore (anti-loop)
//   5  cualquiera + otro bot                                     -> ignore
//   6  message + humano + DM (im)                                -> ignore
//   7  app_mention + humano + fuera de canal REQ                 -> ignore
//   8  message + humano + reply sin mencion                      -> ignore
//   9  edit/delete                                               -> ignore
//   10 message + Claude firmado + canal REQ + raiz               -> ignore (gemelo del app_mention)
//   11 cualquier mencion/texto libre del usuario (no firmado)    -> ignore
//
// NOTA DE-DUP (REQ duplicados):
//   Un posteo firmado por Claude que menciona a Miles en un canal REQ dispara
//   DOS eventos Slack: `message` y `app_mention`, ambos con la firma. Para
//   capturar el REQ una sola vez, el evento CANONICO de captura es `app_mention`
//   (senal explicita de intencion hacia Miles). El `message` gemelo se descarta.
//
// NOTA INTERACCION POR TEXTO LIBRE (eliminado el follow-up):
//   La UNICA interaccion habilitada usuario->Miles via texto es la firmada por
//   Claude (captura de REQ). Mencionar a Miles a mano o escribir texto libre en
//   un hilo NO dispara nada en este router. Las interacciones ricas del usuario
//   (botones, inputs, modales) NO entran por la Events API: Slack las envia como
//   interactivity payloads a /webhook/slack-actions (router aparte). Por eso aca
//   no existe rama de follow-up: seria estructuralmente imposible que reciba esas
//   interacciones, y solo atraparia texto libre, que esta deshabilitado.
// ============================================================================

const body  = $json.body || {};
const event = body.event || {};

const MILES_ID  = 'U0ANEJ5BRPZ';
const CLAUDE_ID = 'U0AHZHTQE22';
const REQ_CHANNELS = ['C0AJ2599DA6','C0AJ67HK0ES','C0AK2PW5BGQ','C0AKNPCNNSU','C0AJMRFP0TD','C0ARDGP8134'];
const CLAUDE_SIGNATURES = ['Sent using','Sent with','Sent via','Sent from','Sent by',
  'Enviado usando','Enviado mediante','Enviado con','Enviado vía','Enviado via','Enviado por','Enviado desde'];

const text = event.text || '';
const ignore = (reason) => [{ json: { action: 'ignore', _reason: reason } }];

// --- Eje 1: tipo de evento --------------------------------------------------
const eventType = event.type || '';
const subtype   = event.subtype || '';
const isEditDelete = subtype === 'message_changed' || subtype === 'message_deleted' || !!event.edited;

// (9) edit/delete -> ignore
if (isEditDelete) return ignore('edit_or_delete');

// (2) app_home_opened -> app_home  (solo humano; los bots no abren Home)
if (eventType === 'app_home_opened') {
  if (!event.user || event.user === MILES_ID) return ignore('home_non_human');
  return [{ json: { action: 'app_home', user_id: event.user } }];
}

// --- Eje 2: origen ----------------------------------------------------------
// (4) el propio Miles -> ignore (anti-loop)
if (event.user === MILES_ID || event.bot_id) {
  // bot_id cubre (5) otro bot y (4) Miles posteando como bot
  // pero Claude firmado puede venir con bot_id? No: Claude postea como usuario humano.
  // Excepcion: si es Claude firmado lo evaluamos abajo, antes de descartar por bot.
  const sigOK = CLAUDE_SIGNATURES.some(s => text.includes(s)) && text.includes(CLAUDE_ID);
  if (!sigOK) return ignore('bot_or_miles');
}

const isClaudeSigned = CLAUDE_SIGNATURES.some(s => text.includes(s)) && text.includes(CLAUDE_ID);

// --- Eje 3: ubicacion + intencion ------------------------------------------
const channel     = event.channel || '';
const isReqChannel = REQ_CHANNELS.includes(channel);
const isDM        = event.channel_type === 'im';
const isRoot      = !event.thread_ts || event.thread_ts === event.ts;

// (6) DM entrante -> ignore (Miles solo reacciona a lo que el inicia)
if (isDM) return ignore('dm_inbound');

// --- (10) DE-DUP: descartar el `message` gemelo del posteo firmado ----------
// Un posteo firmado por Claude que menciona a Miles dispara `message` Y
// `app_mention`. La captura se hace SOLO por `app_mention` (abajo). Cualquier
// evento `message` firmado se descarta para no duplicar el REQ.
if (eventType === 'message' && isClaudeSigned) {
  return ignore('claude_signed_message_dedup');
}

// --- (3) Captura de REQ: app_mention + Claude firmado + canal REQ + raiz ----
if (eventType === 'app_mention' && isClaudeSigned && isReqChannel && isRoot) {
  return [{ json: {
    action: 'capture_req',
    thread_ts: event.ts,
    channel_id: channel,
    user_id: event.user,
    message_text: text.replace(/<@[A-Z0-9]+>/g, '').trim(),
    source: 'claude'
  }}];
}

// (7) app_mention fuera de canal REQ -> ignore
if (eventType === 'app_mention' && !isReqChannel) return ignore('mention_outside_req');

// (11) app_mention en canal REQ sin firma (mano del usuario) -> ignore
//      Incluye menciones en raiz y en reply: texto libre no habilitado.
if (eventType === 'app_mention') return ignore('mention_unsigned_noop');

// (8) message (humano, sin firma) -> ignore (texto libre no habilitado)
return ignore('no_match');

// ============================================================================
// miles-slack-event-router · Build App Home View
// ----------------------------------------------------------------------------
// Arma la vista del App Home: intro personalizada (nombre + area) + capacidades.
// El nombre y el area salen de users.info (nodo previo). El area se infiere del
// campo `title` del perfil, con el MISMO criterio que el skill ardua-req-definition.
// ============================================================================

const info = $json;  // respuesta de users.info
const profile = (info.user && info.user.profile) || {};
const userId  = (info.user && info.user.id) || $('Classify Event').first().json.user_id;

const firstName = profile.first_name || profile.display_name || profile.real_name || 'che';
const title     = profile.title || '';

// --- Inferencia de area (criterio del skill) --------------------------------
const AREA_KEYWORDS = [
  { area: 'Finance & Accounting', kw: ['finance','finanzas','accounting','contabilidad','cfo'] },
  { area: 'Legal & Compliance',   kw: ['legal','compliance','legales'] },
  { area: 'Operations',           kw: ['operations','operaciones'] },
  { area: 'Sales & Partnerships', kw: ['sales','comercial','partnerships'] },
  { area: 'Trading Desk',         kw: ['trading','mesa','trading desk'] },
  { area: 'Management',           kw: ['ceo','coo','management','direccion','dirección','directorio'] },
];
function inferArea(t) {
  if (!t) return null;
  // Si hay separador, el area esta despues
  let seg = t;
  const sep = t.match(/[|\/,]/);
  if (sep) seg = t.split(/[|\/,]/).pop().trim();
  const low = (seg + ' ' + t).toLowerCase();
  for (const { area, kw } of AREA_KEYWORDS) {
    if (kw.some(k => low.includes(k))) return area;
  }
  return null;
}
const area = inferArea(title);
const areaLine = area
  ? `Trabajás en *${area}*.`
  : `Sos parte del equipo de Ardua.`;

// --- Block Kit de la vista --------------------------------------------------
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `Hola ${firstName} 👋`, emoji: true } },
  { type: 'section', text: { type: 'mrkdwn',
    text: `${areaLine}\nSoy *Miles*, tu asistente de Producto en Slack. Esto es lo que puedo hacer por vos:` } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*📝 Capturar requerimientos*\nCuando describís una necesidad en el canal de tu área, la convierto en un requerimiento y lo registro en Jira automáticamente.' } },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*✅ Gestionar aprobaciones*\nSi un requerimiento necesita el visto bueno del líder del área, le acerco la decisión con botones para aprobar o rechazar.' } },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*🔔 Avisarte cómo avanza*\nTe notifico en el hilo original cada vez que tu requerimiento cambia de estado: enviado a desarrollo, en curso, completado, y más.' } },
  { type: 'divider' },
  { type: 'context', elements: [{ type: 'mrkdwn',
    text: '💡 Para crear un requerimiento, escribime en el canal `#req-product-` de tu área o pedíselo a Claude.' }] },
];

const view = { type: 'home', blocks };

return [{ json: { user_id: userId, view: JSON.stringify(view) } }];

// ============================================================================
// miles-slack-event-router · Resolve Profile  (v3 — precedencia Role > Group)
// ----------------------------------------------------------------------------
// Orden de precedencia (ver miles-home-discovery.md):
//   1. Role contiene "Product"  -> 'producto'  (precede a TODO; ej. Head of Product)
//   2. Group Head / C-Level     -> 'lider'
//   3. Group Analyst            -> 'stakeholder'
//   4. Group Manager/Specialist + req.ticket.take -> 'tecnico'
//                               sin req.ticket.take -> 'producto'
//   5. fallback (sin match / sin Group) -> 'producto'
//
// Flag adicional: is_tech_lead = (perfil tecnico Y Role == "Technical Lead").
// Suma la seccion de Refinamiento en el builder tecnico.
//
// Exporta tambien: jira_id (assignee para queries), business_area_id (pageId,
// para resolver el nombre del area), first_name.
// ============================================================================

const stkRes = $('Query Stakeholder by Slack ID').first().json.results || [];
const slackUser = $('Classify Event').first().json.user_id;
const info = $('Get Home User Info').first().json;
const sProfile = (info.user && info.user.profile) || {};
const firstName = sProfile.first_name || sProfile.display_name || sProfile.real_name || 'che';

const capRes = $('Query Capability — ticket.take').first().json.results || [];
const ticketTakeId = capRes[0] ? capRes[0].id : null;

function emit(profile, reason, extra={}) {
  return [{ json: {
    profile, _reason: reason, user_id: slackUser, first_name: firstName,
    is_tech_lead: false, jira_id: null, business_area_id: null, ...extra
  } }];
}

if (stkRes.length === 0) return emit('producto', 'no_stakeholder_match', { group: [], capabilities: [], role: '' });

const props = stkRes[0].properties || {};
const group = (props['Group']?.multi_select || []).map(g => g.name);
const capabilities = (props['Capabilities']?.relation || []).map(r => r.id);
const businessAreaId = (props['Business Area']?.relation || [])[0]?.id || null;
const role = props['Role']?.rich_text?.[0]?.plain_text || '';
const jiraId = props['Jira ID']?.rich_text?.[0]?.plain_text || null;

const base = { group, capabilities, role, jira_id: jiraId, business_area_id: businessAreaId };

// 1) Role con "Product" manda
if (/product/i.test(role)) return emit('producto', 'role_product', base);

// 2) Sin Group -> fallback
if (group.length === 0) return emit('producto', 'no_group', base);

// 3) Head / C-Level -> lider
if (group.includes('C-Level') || group.includes('Head')) return emit('lider', 'group_head', base);

// 4) Analyst -> stakeholder
if (group.includes('Analyst')) return emit('stakeholder', 'group_analyst', base);

// 5) Manager / Specialist -> tecnico si tiene ticket.take, si no producto
if (group.includes('Manager') || group.includes('Specialist')) {
  const hasTicketTake = ticketTakeId && capabilities.includes(ticketTakeId);
  if (hasTicketTake) {
    const isTL = /technical lead/i.test(role);
    return emit('tecnico', isTL ? 'tech_lead' : 'dev', { ...base, is_tech_lead: isTL });
  }
  return emit('producto', 'manager_pm', base);
}

// fallback
return emit('producto', 'fallback', base);

// Identidad + datos Jira ya resueltos aguas arriba
const bj = $('Build JQL').first().json;
const userId = bj.user_id;
const firstName = bj.first_name || 'che';
const myJiraId = bj.jira_id || null;
// La respuesta del handler puede venir como objeto o string JSON
let _resp = $json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];

// ---------------------------------------------------------------------------
// Aplanador de ADF -> texto plano (para Blocked cause: parrafo o tabla).
// ---------------------------------------------------------------------------
function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
  const kids = Array.isArray(node.content) ? node.content : [];
  if (t === 'tableCell' || t === 'tableHeader') return kids.map(adfToText).filter(Boolean).join(' ').trim();
  if (t === 'tableRow') return kids.map(adfToText).filter(Boolean).join(' · ');
  if (t === 'table')    return kids.map(adfToText).filter(Boolean).join('\n');
  if (t === 'paragraph') return kids.map(adfToText).join('');
  return kids.map(adfToText).filter(Boolean).join('\n');
}
function blockedCauseText(adf){
  if (!adf) return null;
  let txt = adfToText(adf).replace(/\n{2,}/g, '\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (!txt) return null;
  const LIMIT = 280;
  if (txt.length > LIMIT) txt = txt.slice(0, LIMIT - 1).trimEnd() + '…';
  return txt;
}

// Antiguedad en el estado actual (desde statuscategorychangedate)
function daysAgo(iso){
  if (!iso) return null;
  const then = new Date(iso); if (isNaN(then)) return null;
  return Math.floor((Date.now() - then.getTime()) / 86400000);
}
function agoLabel(iso){
  const d = daysAgo(iso);
  if (d === null) return null;
  if (d <= 0) return 'hoy';
  if (d === 1) return 'hace 1 día';
  return `hace ${d} días`;
}
function prioEmoji(prioName){
  const p = (prioName || '').toLowerCase();
  if (p === 'highest') return '🔺';
  if (p === 'high')    return '🔴';
  if (p === 'medium')  return '🟠';
  if (p === 'low')     return '🟢';
  return '⚪';
}
function clip(s, n){ s = String(s||''); return s.length > n ? s.slice(0, n-1).trimEnd() + '…' : s; }

// Normaliza un issue
function row(it){
  const f = it.fields || {};
  const a = f.assignee || null;
  return {
    key: it.key,
    summary: f.summary || '',
    status: f.status ? f.status.name : '',
    assignee: a ? (a.displayName || '') : '',
    assigneeId: a ? (a.accountId || '') : '',
    area: f.customfield_10310 ? (f.customfield_10310.value || f.customfield_10310.name || '') : '',
    priority: f.priority ? f.priority.name : '',
    blockedCause: blockedCauseText(f.customfield_10306),
    blockedSince: f.statuscategorychangedate || null,
    issueType: f.issuetype ? f.issuetype.name : '',
    rank: f.customfield_10019 || ''
  };
}
const rows = issues.map(row);
function inStatus(r, arr){ return arr.includes(r.status); }
const isMine = (r) => myJiraId && r.assigneeId === myJiraId;

function table(caption, header, dataRows){
  const head = header.map(h => ({type:'raw_text', text:h}));
  const body = dataRows.map(cells => cells.map(c => ({type:'raw_text', text:String(c)})));
  return { type:'data_table', caption, rows:[head, ...body] };
}
function emptyNote(txt){ return { type:'context', elements:[{type:'mrkdwn', text:txt}] }; }

// ---------------------------------------------------------------------------
// Card builder (shape slack_icon, sin imagenes, 1 boton Ver en Jira).
// useBlockedCause=true -> body = Blocked cause; si no -> body = summary completo.
// ---------------------------------------------------------------------------
function pwiCard(r, opts){
  opts = opts || {};
  const useBlocked = !!opts.useBlockedCause;
  const ago = agoLabel(r.blockedSince);
  const subParts = [];
  if (r.priority) subParts.push(`${prioEmoji(r.priority)} ${r.priority}`);
  if (r.area)     subParts.push(`📍 ${r.area}`);
  if (ago)        subParts.push(`⏱ ${ago}`);
  let bodyText;
  if (useBlocked) {
    bodyText = r.blockedCause ? r.blockedCause : '_Sin motivo en Blocked cause_';
  } else {
    bodyText = r.summary || '_Sin descripción_';
  }
  const dot = useBlocked ? '🔴' : (r.priority ? prioEmoji(r.priority) : '⚪');
  return {
    type: 'card',
    block_id: `card-${r.key}`,
    slack_icon: { type: 'icon', name: 'rocket' },
    title:    { type: 'mrkdwn', text: `${dot} *${r.key}* · ${clip(r.summary, 80)}` },
    subtitle: { type: 'mrkdwn', text: subParts.join('  ·  ') || '—' },
    body:     { type: 'mrkdwn', text: bodyText },
    actions: [
      {
        type: 'button',
        text: { type: 'plain_text', text: 'Ver en Jira', emoji: true },
        action_id: `view_${r.key}`,
        url: `https://arduasolutions.atlassian.net/browse/${r.key}`
      }
    ]
  };
}
function carousel(cardRows, opts){
  return { type: 'carousel', elements: cardRows.map(r => pwiCard(r, opts)) };
}

// ---------------------------------------------------------------------------
// Reparto de secciones
// ---------------------------------------------------------------------------
// Personales (filtran por mi assignee)
const enCurso       = rows.filter(r => isMine(r) && inStatus(r, ['IN ANALYSIS','IN PROGRESS']));
const porEnriquecer = rows.filter(r => isMine(r) && r.status === 'To Do');
const disponibles   = rows.filter(r => !r.assigneeId && r.status === 'To Do');
const bloqueados    = rows.filter(r => isMine(r) && r.status === 'BLOCKED');
// Global (todos los activos traidos por la query)
const globales = rows
  .filter(r => r.issueType === 'Requirement')
  .sort((a, b) => {
    // LexoRank: el orden lexicografico del string es el orden de ranking.
    // Los sin rank van al final.
    if (!a.rank && !b.rank) return 0;
    if (!a.rank) return 1;
    if (!b.rank) return -1;
    return a.rank < b.rank ? -1 : (a.rank > b.rank ? 1 : 0);
  });

function sectionCarousel(title, rowsArr, opts, emptyTxt){
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${rowsArr.length})`, emoji:true } }];
  out.push(rowsArr.length ? carousel(rowsArr, opts) : emptyNote(emptyTxt));
  return out;
}

const blocks = [
  { type:'section', text:{ type:'mrkdwn', text:`:wave: *Hola, ${firstName}*\nProduct Manager · tu mesa de trabajo` } },
  { type:'actions', elements:[
    { type:'button', style:'primary', text:{type:'plain_text',text:'+ Nuevo requerimiento',emoji:true}, action_id:'new_requirement', value:'new_req' },
    { type:'button', text:{type:'plain_text',text:'Pedir informe',emoji:true}, action_id:'request_report', value:'report' }
  ]},
  { type:'divider' },
  ...sectionCarousel('En curso', enCurso, {}, '_Nada en curso ahora._'),
  { type:'divider' },
  ...sectionCarousel('Por enriquecer', porEnriquecer, {}, '_Nada por enriquecer._'),
  { type:'divider' },
  ...sectionCarousel('Disponibles', disponibles, {}, '_Sin requerimientos disponibles._'),
  { type:'divider' },
  ...sectionCarousel('Bloqueados', bloqueados, { useBlockedCause:true }, '_Sin bloqueos._'),
  { type:'header', text:{ type:'plain_text', text:`Prioridades globales (${globales.length})`, emoji:true } },
  globales.length
    ? table('Prioridades globales', ['Key','Requerimiento','Estado','Prioridad','Área'],
        globales.map(r=>[r.key, r.summary, r.status, r.priority||'—', r.area||'—']))
    : emptyNote('_Sin PWIs activos._'),
  { type:'context', elements:[{ type:'mrkdwn', text:`Miles · ${rows.length} PWIs activos · datos en vivo` }] }
];
const view={type:'home',blocks};
return [{ json:{ user_id:userId, view:JSON.stringify(view) } }];

// Identidad
const bj = $('Build JQL').first().json;
const userId = bj.user_id;
const firstName = bj.first_name || 'che';
const areaName = bj.area_name || 'tu área';
// La respuesta del handler puede venir como objeto o string JSON
let _resp = $json;
if (typeof _resp === 'string') { try { _resp = JSON.parse(_resp); } catch(e){ _resp = {}; } }
if (_resp && _resp.body && !_resp.issues) {
  let b = _resp.body;
  if (typeof b === 'string') { try { b = JSON.parse(b); } catch(e){ b = {}; } }
  _resp = b;
}
const issues = (_resp && _resp.issues) || [];

// --- Aplanador ADF -> texto (Blocked cause: parrafo o tabla) ---
function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
